import {expect} from 'chai';
import {BigNumber} from 'ethers';
import {FeeMode, BPS} from './helper';
import hre from 'hardhat';
import {SmartWalletImplementation, SmartWalletProxy, IERC20Ext, UniswapUniversalRouter} from '../typechain';
import {SignerWithAddress} from '@nomiclabs/hardhat-ethers/signers';
import {loadFixture} from 'ethereum-waffle';
import {keccak256, getCreate2Address, hexConcat, formatBytes32String} from 'ethers/lib/utils';

// This test can only run against a forked BSC mainnet (needs the real, already-deployed
// SmartWalletProxy + real liquidity/pricing for the swap calldata below to still be valid).
// Set MAINNET_FORK / MAINNET_FORK_BLOCK in env/.env.bsc.mainnet and run with `-c bsc -n mainnet`.
describe('UniswapUniversalRouter', async function () {
  let signers: SignerWithAddress[];
  let admin: SignerWithAddress;
  let platformFee = 0;

  let platformWallet = '0x5250b8202AEBca35328E2c217C687E894d70Cd31'; // iOS wallet
  let BNBAddr = '0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE';
  let USDTAddr = '0x55d398326f99059fF775485246999027B3197955';
  let USDCAddr = '0x8AC76a51cc950d9822D68b83fE1Ad97B32Cd580d';
  let USDCHolderAddr = '0xF977814e90dA44bFA03b6295A0616a897441aceC'; // Binance hot wallet
  let slippage = 50; // in BPS unit, which is 0.5%
  let usdcContract: IERC20Ext;
  let usdcDecimals = 18;

  // real, already-deployed SmartWalletProxy on bsc_mainnet, see contracts.json
  const krystalProxyAddr = '0x051DC16b2ECB366984d1074dCC07c342a9463999';
  let krystalProxy: SmartWalletImplementation;

  // constant across every chain, see SwapProxy's verified source
  const swapProxyAddr = '0x0000000085E102724e78eCd2F45DC9cA239Affad';
  // Uniswap's Universal Router deployment on BSC (chain id 56)
  const universalRouterAddr = '0x1906c1d672b88cD1B9aC7593301cA990F94Eae07';

  // Canonical deterministic-deployment proxy, same address on every EVM chain including BSC.
  // Deployed via CREATE2 through here so the adapter always lands at a precomputable address,
  // regardless of `admin`'s real on-chain nonce (it's a well-known test key with real BSC
  // history, so its next nonce isn't reliably 0/1/2 - CREATE2 sidesteps that entirely).
  const CREATE2_FACTORY = '0x4e59b44847b379578588920cA78FbF26c0B4956C';
  const SALT = formatBytes32String('krystal-uur-v1');
  let initCode: string;
  let predictedAddress: string;

  async function deployUniswapUniversalRouter() {
    await admin.sendTransaction({
      to: CREATE2_FACTORY,
      data: hexConcat([SALT, initCode]),
    });
    const uniswapUniversalRouter = (await hre.ethers.getContractAt(
      'UniswapUniversalRouter',
      predictedAddress
    )) as UniswapUniversalRouter;

    // update proxy
    await uniswapUniversalRouter.updateProxyContract(krystalProxyAddr);

    // update swap contract
    let proxy = (await hre.ethers.getContractAt('SmartWalletProxy', krystalProxyAddr)) as SmartWalletProxy;
    const krystalAdminAddr = await proxy.admin();
    const krystalAdmin = await hre.ethers.getImpersonatedSigner(krystalAdminAddr);

    await admin.sendTransaction({
      to: krystalAdmin.address,
      value: hre.ethers.utils.parseEther('1.0'),
    });
    await proxy.connect(krystalAdmin).updateSupportedSwaps([uniswapUniversalRouter.address], true);

    return {uniswapUniversalRouter};
  }

  before(async function () {
    signers = await hre.ethers.getSigners();
    admin = signers[0];

    const UniswapUniversalRouterFactory = await hre.ethers.getContractFactory('UniswapUniversalRouter');
    initCode = UniswapUniversalRouterFactory.getDeployTransaction(admin.address, swapProxyAddr, universalRouterAddr)
      .data as string;
    predictedAddress = getCreate2Address(CREATE2_FACTORY, SALT, keccak256(initCode));
    // Use this as `swapper` (and `recipient`, or omit to default to swapper) when calling
    // Uniswap's /quote + /swap to build the PLACEHOLDER_EXTRA_ARGS below.
    console.log('UniswapUniversalRouter will deploy to:', predictedAddress);

    krystalProxy = (await hre.ethers.getContractAt(
      'SmartWalletImplementation',
      krystalProxyAddr
    )) as SmartWalletImplementation;

    usdcContract = (await hre.ethers.getContractAt('IERC20Ext', USDCAddr)) as IERC20Ext;

    const usdcHolder = await hre.ethers.getImpersonatedSigner(USDCHolderAddr);
    await admin.sendTransaction({to: usdcHolder.address, value: hre.ethers.utils.parseEther('1.0')});
    await usdcContract
      .connect(usdcHolder)
      .transfer(admin.address, hre.ethers.utils.parseUnits('10000.0', usdcDecimals));
  });

  it('Should revert with getExpectedReturn_notSupported', async function () {
    const {uniswapUniversalRouter} = await loadFixture(deployUniswapUniversalRouter);

    await expect(
      krystalProxy.getExpectedReturn({
        swapContract: uniswapUniversalRouter.address,
        srcAmount: BigNumber.from(1),
        tradePath: [],
        feeMode: FeeMode.FROM_SOURCE,
        feeBps: platformFee,
        extraArgs: '0x',
      })
    ).to.be.revertedWith('getExpectedReturn_notSupported');
  });

  it('Should revert with getExpectedReturnWithImpact_notSupported', async function () {
    const {uniswapUniversalRouter} = await loadFixture(deployUniswapUniversalRouter);

    await expect(
      krystalProxy.getExpectedReturnWithImpact({
        swapContract: uniswapUniversalRouter.address,
        srcAmount: BigNumber.from(1),
        tradePath: [],
        feeMode: FeeMode.FROM_SOURCE,
        feeBps: platformFee,
        extraArgs: '0x',
      })
    ).to.be.revertedWith('getExpectedReturnWithImpact_notSupported');
  });

  it('Should revert with getExpectedIn_notSupported', async function () {
    const {uniswapUniversalRouter} = await loadFixture(deployUniswapUniversalRouter);

    await expect(
      krystalProxy.getExpectedIn({
        swapContract: uniswapUniversalRouter.address,
        destAmount: BigNumber.from(1),
        tradePath: [],
        feeMode: FeeMode.FROM_SOURCE,
        feeBps: platformFee,
        extraArgs: '0x',
      })
    ).to.be.revertedWith('getExpectedIn_notSupported');
  });

  it('Should revert with getExpectedInWithImpact_notSupported', async function () {
    const {uniswapUniversalRouter} = await loadFixture(deployUniswapUniversalRouter);

    await expect(
      krystalProxy.getExpectedInWithImpact({
        swapContract: uniswapUniversalRouter.address,
        destAmount: BigNumber.from(1),
        tradePath: [],
        feeMode: FeeMode.FROM_SOURCE,
        feeBps: platformFee,
        extraArgs: '0x',
      })
    ).to.be.revertedWith('getExpectedInWithImpact_notSupported');
  });

  // NOTE for each PLACEHOLDER_* below: capture real values from Uniswap's Trading API
  // (`/quote` then `/swap`, called with header `x-permit2-disabled: true`, `swapper` ==
  // `predictedAddress` logged in `before()` above).
  // IMPORTANT: the commands encoded in the swap calldata must set their recipient to that
  // same adapter address, NOT the end user - MSG_SENDER resolves to `swapProxy` inside the
  // Universal Router's execution context, so anything else silently strands the output.

  // Fork BSC mainnet at block 108553200, then run:

  it('Should swap native to token successfully (BNB -> USDC), routed via universalRouter directly', async function () {
    const {uniswapUniversalRouter} = await loadFixture(deployUniswapUniversalRouter);

    // PLACEHOLDER: swap calldata for 1 BNB (minus platform fee) -> USDC, `to` == universalRouterAddr
    const PLACEHOLDER_EXTRA_ARGS =
      '';
    // PLACEHOLDER: quoted USDC output amount for the swap above
    const PLACEHOLDER_OUTPUT_AMOUNT = BigNumber.from('579275769365393005115');

    const srcAmount = hre.ethers.utils.parseEther('1.0'); // 1 BNB
    const minDestAmount = PLACEHOLDER_OUTPUT_AMOUNT.mul(BPS.sub(slippage)).div(BPS);

    const nativeBalanceBefore = await hre.ethers.provider.getBalance(admin.address);
    const usdcBalanceBefore = await usdcContract.balanceOf(admin.address);

    const tx = await krystalProxy.swap(
      {
        swapContract: uniswapUniversalRouter.address,
        srcAmount: srcAmount,
        minDestAmount,
        tradePath: [BNBAddr, USDCAddr],
        feeMode: FeeMode.FROM_SOURCE,
        feeBps: platformFee,
        platformWallet: platformWallet,
        extraArgs: PLACEHOLDER_EXTRA_ARGS,
      },
      {
        value: srcAmount,
      }
    );
    const receipt = await tx.wait();
    const gasCost = receipt.gasUsed.mul(tx.gasPrice as BigNumber);

    const nativeBalanceAfter = await hre.ethers.provider.getBalance(admin.address);
    const usdcBalanceAfter = await usdcContract.balanceOf(admin.address);

    // admin also pays gas from the same native balance, so back it out to isolate the swap input
    expect(nativeBalanceBefore.sub(nativeBalanceAfter).sub(gasCost)).to.equal(srcAmount);
    expect(usdcBalanceAfter.sub(usdcBalanceBefore)).to.be.gte(minDestAmount);
  });

  it('Should swap token to token successfully (USDC -> USDT), routed via swapProxy', async function () {
    const {uniswapUniversalRouter} = await loadFixture(deployUniswapUniversalRouter);

    // PLACEHOLDER: swap calldata for 100 USDC (minus platform fee) -> USDT, `to` == swapProxyAddr
    const PLACEHOLDER_EXTRA_ARGS =
      '';
    // PLACEHOLDER: quoted USDT output amount for the swap above
    const PLACEHOLDER_OUTPUT_AMOUNT = BigNumber.from('100061504956466162122');

    const srcAmount = hre.ethers.utils.parseUnits('100.0', usdcDecimals);
    const minDestAmount = PLACEHOLDER_OUTPUT_AMOUNT.mul(BPS.sub(slippage)).div(BPS);

    await usdcContract.approve(krystalProxy.address, srcAmount);

    const usdtContract = (await hre.ethers.getContractAt('IERC20Ext', USDTAddr)) as IERC20Ext;
    const usdcBalanceBefore = await usdcContract.balanceOf(admin.address);
    const usdtBalanceBefore = await usdtContract.balanceOf(admin.address);

    await krystalProxy.swap({
      swapContract: uniswapUniversalRouter.address,
      srcAmount: srcAmount,
      minDestAmount,
      tradePath: [USDCAddr, USDTAddr],
      feeMode: FeeMode.FROM_SOURCE,
      feeBps: platformFee,
      platformWallet: platformWallet,
      extraArgs: PLACEHOLDER_EXTRA_ARGS,
    });

    const usdcBalanceAfter = await usdcContract.balanceOf(admin.address);
    const usdtBalanceAfter = await usdtContract.balanceOf(admin.address);

    expect(usdcBalanceBefore.sub(usdcBalanceAfter)).to.equal(srcAmount);
    expect(usdtBalanceAfter.sub(usdtBalanceBefore)).to.be.gte(minDestAmount);
  });

  it('Should swap token to native successfully (USDC -> BNB), routed via swapProxy', async function () {
    const {uniswapUniversalRouter} = await loadFixture(deployUniswapUniversalRouter);

    // PLACEHOLDER: swap calldata for 1000 USDC (minus platform fee) -> BNB, `to` == swapProxyAddr
    const PLACEHOLDER_EXTRA_ARGS =
      '';
    // PLACEHOLDER: quoted BNB output amount for the swap above
    const PLACEHOLDER_OUTPUT_AMOUNT = BigNumber.from('172438497241688089');

    const srcAmount = hre.ethers.utils.parseUnits('100.0', usdcDecimals);
    const minDestAmount = PLACEHOLDER_OUTPUT_AMOUNT.mul(BPS.sub(slippage)).div(BPS);

    await usdcContract.approve(krystalProxy.address, srcAmount);

    const usdcBalanceBefore = await usdcContract.balanceOf(admin.address);
    const nativeBalanceBefore = await hre.ethers.provider.getBalance(admin.address);

    const tx = await krystalProxy.swap({
      swapContract: uniswapUniversalRouter.address,
      srcAmount: srcAmount,
      minDestAmount,
      tradePath: [USDCAddr, BNBAddr],
      feeMode: FeeMode.FROM_SOURCE,
      feeBps: platformFee,
      platformWallet: platformWallet,
      extraArgs: PLACEHOLDER_EXTRA_ARGS,
    });
    const receipt = await tx.wait();
    const gasCost = receipt.gasUsed.mul(tx.gasPrice as BigNumber);

    const usdcBalanceAfter = await usdcContract.balanceOf(admin.address);
    const nativeBalanceAfter = await hre.ethers.provider.getBalance(admin.address);

    expect(usdcBalanceBefore.sub(usdcBalanceAfter)).to.equal(srcAmount);
    // admin also pays gas from the same native balance, so add it back to isolate the swap output
    expect(nativeBalanceAfter.sub(nativeBalanceBefore).add(gasCost)).to.be.gte(minDestAmount);
  });
});
